// 假设 $input.all() 是获取所有输入数据的方法
const inputData = $input.all().map(item => {
  const sn=$("Webhook").all()[0].json.body.sn;
  return {
    retroid:item.json.sn??sn,
    retroid_id:item.json.retroid_id,
    procedure_detail_id:item.json.procedure_detail_id,
    create_time:item.json.createtime,
    data:item.json.data

  }
}); // 在实际使用中获取数据
const response = {
  code:200,
  data:inputData
};

// 返回处理后的结果
return response;

// 遍历输入项并处理每条数据
let result = {
    code: 0,
    message: '处理成功'
};

for (const item of $input.all()) {
    const requestData = item.json.body;

    // 校验工序ID必填
    if (!requestData.procedure_detail_id) {
        return {
            code: 1,
            message: '请选择工序！',
            data: null
        };
    }

    // 判断SN和工单号哪个存在
    if (requestData.sn) {
        result = {
            code: 2,
            sn: requestData.sn,
            procedure_id: requestData.procedure_id  // 保留工序ID
        };
    } else if (requestData.jobNumber) {  // 修正了原代码中的拼写错误
        result = {
            code: 3,
            jobNumber: requestData.jobNumber,
            procedure_id: requestData.procedure_id  // 保留工序ID
        };
    } else {
        return {
            code: 4,
            message: '必须提供SN或工单号',
            data: null
        };
    }

    // 如果只需要处理第一条有效数据就跳出循环
    break;
}

return result;
